                    "actionAttributes": "",
                    "groupBy": false,
                    "group": "",
                    "assignmentId": "c6542741ff13101035be517f793bf1bb",
                    "confirmationRequired": false,
                    "confirmationMessage": "",
                    "tooltip": "Search for Record ",
