    ///not yet working as it should be. Goal is a text-only element like catalog "label"
    _buildLabel: function() {
        return {
            name: this.name,
            label: this.label,
            type: "string", //"documentation_field",///container? xml? formatter? annotation?
            internalType: "string",

            // UI behavior
            visible: true,
            readonly: true,
            mandatory: false,
            canWrite: false,
            canCreate: false,
            canRead: true,
            // Rendering
            value: this._getOption("value", ""),
            displayValue: this._getOption("displayValue", ""),

            // Explicitly opt out of data handling
            isDataField: false
        };
    },

    _buildAnnotation: function() {
        return {
            name: this.name,
            type: "annotation",
            internalType: "annotation",

            // UI behavior
            visible: true,
            readonly: true,
            mandatory: false,
            canWrite: false,
            canCreate: false,
            canRead: true,
            text: this._getOption("displayValue", ""),
            // Rendering
            defer: false,

            // Explicitly opt out of data handling
            isDataField: false
        };
    },
    /**
     * Optional generator-supplied rules for client-side validation (nfValidation).
     * Pass as options.nfValidation — only JSON-safe fields are copied.
     */
    _normalizeNfValidationForClient: function() {
        var o = {};
        const validationRule = this.options.nfValidation;
        if (!validationRule || typeof validationRule !== 'object') {
            this.options.nfValidation = o;
            return;
        }
        if (validationRule.readOnly === true || (validationRule.readOnly + '') === 'true') {
            this.options.nfValidation = {
                readOnly: true,
                readonly: true
            };
            return;
        }
        o.readOnly = false;
        o.readonly = false;
        if (Array.isArray(validationRule.allowedValues)) {
            o.allowedValues = validationRule.allowedValues;
        }
        if (!gs.nil(validationRule.maxLength)) {
            var ml = parseInt(validationRule.maxLength, 10);
            if (!isNaN(ml)) {
                o.maxLength = ml;
            }
        }
        if (!gs.nil(validationRule.minLength)) {
            var nl = parseInt(validationRule.minLength, 10);
            if (!isNaN(nl)) {
                o.minLength = nl;
            }
        }
        o.mandatory = validationRule.mandatory === true || (validationRule.mandatory+'') === 'true';
        if (validationRule.type) {
            o.type = String(validationRule.type).toLowerCase();
        }
        if (typeof validationRule.regex === 'string' && validationRule.regex.length) {
            //o.regex = validationRule.regex;
			if (gs.nil(this.fieldData.fieldRegex)) {
				this.fieldData.fieldRegex = [{
                "pattern": validationRule.regex,
                "placeholder": "",
                "guidanceText": "Value does not match required pattern",
                "type": "suggestion"
            }];
			}
        }
        this.options.nfValidation = o;
    },

    _buildFieldWithCommon: function(obj) {
        const readOnly = this._getOption('readonly', false);
        const field = Object.assign({
            "name": this.name,
            "label": this.label,
            "defer": true,
            "visible": true,
            "readonly": readOnly,
            "mandatory": this._getOption('mandatory', false),
            "isEncrypted": false,
            "encryptionContext": "",
            "sys_readonly": this._getOption('sys_readonly', readOnly),
            "canWrite": !readOnly,
            "canRead": true,
            "canCreate": !readOnly,
            "fieldHint": this._getOption('fieldHint', null),
            "fieldLayout": this._getOption("fieldLayout", {
                "layout": this._getOption("layout", "vertical")
            }),
			"fieldRegex": this._getOption('fieldRegex', []), ///need to integrate and test more fully. use regex from nfValidation
			/*[
            {
                "pattern": "^[0-5]*$",
                "placeholder": "test",
                "guidanceText": "Invalid Value. Please enter correct value",
                "type": "suggestion"
            }
        ],*/
            "isGlideVar": false,
            "value": this._getOption('value', ""),
            "displayValue": this._getOption('displayValue', ""),
            "originalValue": this._getOption('value', "")
        }, obj);

        if (Object.keys(this.options.nfValidation).length !== 0) {
            field.nfValidation = this.options.nfValidation;
        }
        return field;
    },

    _getOption: function(name, defaultVal) {
        if (!this.options) {
            return defaultVal || null;
        }
        //validation options override field options to avoid conflicts
        if (['maxLength', 'minLength', 'readOnly', 'readonly', 'mandatory'].indexOf(name) !== -1) {
            if (Object.prototype.hasOwnProperty.call(this.options.nfValidation, name)) {
                return this.options.nfValidation[name];
            }
        }
        if (Object.prototype.hasOwnProperty.call(this.options, name)) {
            return this.options[name];
        }
        return defaultVal;
    },

    toJSON: function() {
        return this.fieldData;
    },

    toString: function() {
        return this.name;
    },

    type: 'NextField'
};
